import { useState } from 'react';
import { supabase } from './supabaseClient';

export default function Auth() {
  const [loading, setLoading] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) return alert("Plotëso të dhënat!");
    setLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) alert(error.message);
    setLoading(false);
  };

  const handleSignUp = async (e) => {
    e.preventDefault();
    if (!email || !password) return alert("Plotëso të dhënat!");
    setLoading(true);
    const { error } = await supabase.auth.signUp({ email, password });
    if (error) alert(error.message);
    else alert("Sukses! Provo të logohesh tani.");
    setLoading(false);
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '80vh' }}>
      <div style={{ 
        background: 'white', padding: '40px', borderRadius: '16px', 
        boxShadow: '0 10px 30px rgba(0,0,0,0.05)', width: '100%', maxWidth: '400px',
        textAlign: 'center'
      }}>
        <h2 style={{ margin: '0 0 10px', fontSize: '24px', color: '#111' }}>Mirësevjen në GlowAI ✨</h2>
        <p style={{ color: '#666', marginBottom: '30px', fontSize: '14px' }}>Hyr për të ruajtur produktet e tua.</p>
        
        <form style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <input 
            type="email" placeholder="Emaili yt" value={email} onChange={(e) => setEmail(e.target.value)} 
            style={{ padding: '12px 16px', borderRadius: '8px', border: '1px solid #e0e0e0', fontSize: '15px', outline: 'none' }}
          />
          <input 
            type="password" placeholder="Fjalëkalimi" value={password} onChange={(e) => setPassword(e.target.value)} 
            style={{ padding: '12px 16px', borderRadius: '8px', border: '1px solid #e0e0e0', fontSize: '15px', outline: 'none' }}
          />
          
          <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
            <button onClick={handleLogin} disabled={loading} style={{ 
              flex: 1, padding: '12px', background: '#111', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '600'
            }}>Log In</button>
            <button onClick={handleSignUp} disabled={loading} style={{ 
              flex: 1, padding: '12px', background: '#f0f0f0', color: '#333', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '600'
            }}>Sign Up</button>
          </div>
        </form>
      </div>
    </div>
  );
}
